#include <iostream>
using namespace std;

int main() {
    char str[] = "Hello, C++!";

    // 统计字符个数
    int count = 0;
    for (int i = 0; str[i] != '\0'; i++) {
        count++;
    }
    cout << "字符个数：" << count << endl;

    // 转换为大写
    for (int i = 0; str[i] != '\0'; i++) {
        if (str[i] >= 'a' && str[i] <= 'z') {
            str[i] -= 32;
        }
    }
    cout << "大写：" << str << endl;

    return 0;
}

#include <iostream>
#include <cstring>
using namespace std;

bool check(char str[], int len) {
    if (len < 6 || len > 12) return false;
    bool hasSpecial = false;
    for (int i = 0; i < len; i++) {
        char c = str[i];
        if (!((c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z') || 
              (c >= '0' && c <= '9') || c == '!' || c == '@' || 
              c == '#' || c == '$' || c == '%' || c == '^')) {
            return false;
        }
        if (c == '!' || c == '@' || c == '#' || c == '$' || 
            c == '%' || c == '^') {
            hasSpecial = true;
        }
    }
    return hasSpecial;
}

int main() {
    char pwd[100];
    cin >> pwd;
    if (check(pwd, strlen(pwd))) {
        cout << "YES" << endl;
    } else {
        cout << "NO" << endl;
    }
    return 0;
}
